-- Kisah person index — notable Sahabat (companions of the Prophet ﷺ),
-- starting with the widely-taught core figures. Written from established,
-- universally-taught Islamic history, not copied from any single book.

INSERT OR IGNORE INTO kisah_person (slug, category_slug, name_id, name_ar, title_id, summary_id, full_story_slug, sort_order) VALUES
('abu-bakar', 'kisah-sahabat', 'Abu Bakar Ash-Shiddiq', 'أَبُو بَكْرٍ الصِّدِّيق رَضِيَ اللهُ عَنْهُ', 'Khalifah Pertama, Sahabat Terdekat Nabi',
 'Abu Bakar RA adalah orang dewasa pertama yang memeluk Islam dan sahabat paling dekat Nabi Muhammad ﷺ, mendampinginya bahkan saat hijrah ke Madinah bersembunyi di Gua Tsur. Gelar "Ash-Shiddiq" (yang membenarkan) disematkan karena ia langsung mempercayai peristiwa Isra Mi''raj tanpa keraguan sedikit pun. Sepeninggal Nabi ﷺ, ia terpilih sebagai khalifah pertama dan dengan tegas memerangi kaum murtad serta nabi-nabi palsu, menjaga keutuhan Islam di masa paling rawan sepanjang sejarahnya.', NULL, 1),
('umar-bin-khattab', 'kisah-sahabat', 'Umar bin Khattab', 'عُمَر بْنُ الْخَطَّابِ رَضِيَ اللهُ عَنْهُ', 'Khalifah Kedua, Al-Faruq',
 'Umar bin Khattab RA dikenal sebagai pribadi yang tegas dan pemberani, bahkan sempat menjadi penentang keras Islam sebelum keislamannya sendiri menjadi titik balik yang memperkuat posisi kaum muslimin di Makkah. Digelari "Al-Faruq" (pembeda antara benar dan salah), ia memimpin sebagai khalifah kedua dengan perluasan wilayah Islam yang pesat, membangun sistem pemerintahan, baitulmal, dan kalender Hijriyah. Kesederhanaannya sebagai pemimpin — berpatroli malam sendiri memeriksa kondisi rakyatnya — menjadi teladan keadilan yang legendaris.', NULL, 2),
('utsman-bin-affan', 'kisah-sahabat', 'Utsman bin Affan', 'عُثْمَان بْنُ عَفَّانَ رَضِيَ اللهُ عَنْهُ', 'Khalifah Ketiga, Dzun Nurain',
 'Utsman bin Affan RA dikenal sebagai saudagar kaya yang sangat dermawan, menikahi dua putri Nabi ﷺ secara berturutan sehingga digelari "Dzun Nurain" (pemilik dua cahaya). Ia berjasa besar membiayai sumur untuk kaum muslimin di Madinah dan mempersiapkan pasukan dalam masa sulit. Sebagai khalifah ketiga, ia menstandardisasi mushaf Al-Qur''an menjadi satu bacaan resmi (Mushaf Utsmani) yang digunakan hingga hari ini, sebuah warisan besar yang menjaga keaslian teks Al-Qur''an di seluruh dunia.', NULL, 3),
('ali-bin-abi-thalib', 'kisah-sahabat', 'Ali bin Abi Thalib', 'عَلِيّ بْنُ أَبِي طَالِبٍ رَضِيَ اللهُ عَنْهُ', 'Khalifah Keempat, Menantu Nabi',
 'Ali bin Abi Thalib RA adalah sepupu sekaligus menantu Nabi Muhammad ﷺ, memeluk Islam sejak usia belia dan dikenal karena keberanian serta kedalaman ilmunya. Ia pernah menggantikan posisi Nabi ﷺ di tempat tidurnya pada malam hijrah yang penuh bahaya demi mengelabui rencana pembunuhan kaum Quraisy. Sebagai khalifah keempat, ia menghadapi masa-masa penuh gejolak politik dengan tetap berpegang pada prinsip keadilan, dan hingga kini dikenal sebagai salah satu sumber utama ilmu fikih dan hikmah di kalangan umat Islam.', NULL, 4),
('khalid-bin-walid', 'kisah-sahabat', 'Khalid bin Walid', 'خَالِد بْنُ الْوَلِيدِ رَضِيَ اللهُ عَنْهُ', 'Saifullah, Pedang Allah',
 'Khalid bin Walid RA awalnya adalah panglima pasukan Quraisy yang mengalahkan kaum muslimin di Perang Uhud, namun setelah masuk Islam ia menjadi salah satu panglima perang paling brilian dalam sejarah Islam. Nabi Muhammad ﷺ menggelarinya "Saifullah" (Pedang Allah) atas kegigihannya menyelamatkan pasukan muslim dalam Perang Mu''tah. Ia tidak pernah kalah dalam satu pertempuran pun sepanjang kariernya, namun tetap rendah hati — berwasiat agar tidak diratapi berlebihan dan mengenang bahwa ia wafat di atas ranjang, bukan di medan perang seperti harapannya.', NULL, 5),
('bilal-bin-rabah', 'kisah-sahabat', 'Bilal bin Rabah', 'بِلَال بْنُ رَبَاحٍ رَضِيَ اللهُ عَنْهُ', 'Muazin Pertama Islam',
 'Bilal bin Rabah RA adalah budak dari Habasyah (Ethiopia) yang disiksa dengan kejam oleh majikannya karena keteguhannya memeluk Islam, hanya mengucapkan "Ahad, Ahad" (Yang Maha Esa) di tengah siksaan. Ia dibebaskan oleh Abu Bakar RA dan kemudian dipilih langsung oleh Nabi ﷺ sebagai muazin pertama dalam Islam karena suaranya yang merdu dan tegas. Kisahnya menjadi simbol abadi kesetaraan dalam Islam — bahwa kemuliaan seseorang diukur dari ketakwaan, bukan status sosial atau warna kulit.', NULL, 6),
('abu-hurairah', 'kisah-sahabat', 'Abu Hurairah', 'أَبُو هُرَيْرَةَ رَضِيَ اللهُ عَنْهُ', 'Perawi Hadits Terbanyak',
 'Abu Hurairah RA memeluk Islam pada tahun ketujuh Hijriyah dan menghabiskan sisa hidupnya senantiasa mendampingi Nabi Muhammad ﷺ demi menghafal setiap sabdanya. Karena kedekatannya yang luar biasa dan daya ingatnya yang kuat, ia menjadi sahabat dengan riwayat hadits terbanyak yang sampai kepada umat Islam hingga kini — menjadi salah satu pilar utama penjagaan sunnah Nabi ﷺ setelah wafatnya.', NULL, 7),
('salman-al-farisi', 'kisah-sahabat', 'Salman Al-Farisi', 'سَلْمَان الْفَارِسِيّ رَضِيَ اللهُ عَنْهُ', 'Pengusul Strategi Parit',
 'Salman Al-Farisi RA berasal dari Persia dan melakukan perjalanan panjang mencari kebenaran melalui berbagai guru agama sebelum akhirnya bertemu dan memeluk Islam bersama Nabi Muhammad ﷺ di Madinah. Ia dikenal karena mengusulkan strategi menggali parit (khandaq) untuk mempertahankan Madinah dari pengepungan pasukan sekutu — taktik yang belum pernah dikenal bangsa Arab sebelumnya dan terbukti menyelamatkan kaum muslimin. Nabi ﷺ menyebutnya sebagai bagian dari Ahlul Bait karena kedekatan dan keteladanannya.', NULL, 8),
('zaid-bin-tsabit', 'kisah-sahabat', 'Zaid bin Tsabit', 'زَيْد بْنُ ثَابِتٍ رَضِيَ اللهُ عَنْهُ', 'Penulis Wahyu & Penghimpun Mushaf',
 'Zaid bin Tsabit RA bergabung sebagai penulis wahyu resmi Nabi Muhammad ﷺ sejak usia muda karena kecerdasannya, termasuk mempelajari bahasa Ibrani dan Suryani atas perintah Nabi ﷺ untuk keperluan korespondensi. Sepeninggal Nabi ﷺ, ia dipercaya memimpin tim penghimpunan Al-Qur''an menjadi satu mushaf di masa Abu Bakar RA, lalu menyempurnakan standardisasinya di masa Utsman RA — menjadikannya tokoh kunci dalam sejarah pelestarian teks Al-Qur''an.', NULL, 9),
('aisyah-binti-abu-bakar', 'kisah-sahabat', 'Aisyah binti Abu Bakar', 'عَائِشَةُ بِنْتُ أَبِي بَكْرٍ رَضِيَ اللهُ عَنْهَا', 'Ummul Mukminin, Ulama Wanita Terkemuka',
 'Aisyah RA, putri Abu Bakar RA dan istri Nabi Muhammad ﷺ, dikenal karena kecerdasan dan daya ingatnya yang luar biasa dalam menjaga hadits-hadits Nabi ﷺ, khususnya yang berkaitan dengan kehidupan rumah tangga dan ibadah. Setelah wafatnya Nabi ﷺ, para sahabat dan tabi''in banyak merujuk kepadanya untuk memahami berbagai persoalan agama, menjadikannya salah satu ulama wanita paling berpengaruh dalam sejarah Islam.', NULL, 10),
('fatimah-az-zahra', 'kisah-sahabat', 'Fatimah Az-Zahra', 'فَاطِمَةُ الزَّهْرَاءُ رَضِيَ اللهُ عَنْهَا', 'Putri Kesayangan Nabi',
 'Fatimah Az-Zahra RA adalah putri bungsu Nabi Muhammad ﷺ yang paling dicintainya, dikenal karena kesederhanaan hidupnya meski sebagai putri seorang pemimpin besar. Ia menikah dengan Ali bin Abi Thalib RA dan melahirkan keturunan yang meneruskan garis keluarga Nabi ﷺ (Ahlul Bait). Nabi ﷺ pernah bersabda bahwa Fatimah adalah pemimpin wanita penghuni surga, menjadikannya teladan utama akhlak dan ketakwaan bagi wanita muslimah sepanjang zaman.', NULL, 11),
('mushab-bin-umair', 'kisah-sahabat', 'Mush''ab bin ''Umair', 'مُصْعَب بْنُ عُمَيْرٍ رَضِيَ اللهُ عَنْهُ', 'Duta Islam Pertama ke Madinah',
 'Mush''ab bin ''Umair RA berasal dari keluarga terpandang dan kaya raya di Makkah, namun rela meninggalkan seluruh kemewahannya demi memeluk Islam. Ia diutus Nabi ﷺ sebagai duta dakwah pertama ke Madinah sebelum peristiwa hijrah, dan berhasil mengislamkan banyak penduduknya lewat kelembutan dan kesabaran dalam berdakwah. Ia gugur syahid dalam Perang Uhud dengan kain kafan yang bahkan tidak cukup menutupi seluruh tubuhnya — kontras menyayat dengan kekayaannya di masa lalu, menjadi teladan tentang kesungguhan mengutamakan akhirat.', NULL, 12);
